pub struct MockSshExecutor {
    expected_commands: Vec<ExpectedCommand>,
    connectivity_result: Option<Result<bool, FleetError>>,
    call_count: Arc<AtomicUsize>,
    max_concurrent: Arc<AtomicUsize>,
}

struct ExpectedCommand {
    pattern: String,  // Command substring to match
    response: MockResponse,
}

enum MockResponse {
    Success { stdout: String, stderr: String, exit_code: i32 },
    Failure { error: FleetError },
    Delay { duration: Duration, then: Box<MockResponse> },
}

impl MockSshExecutor {
    pub fn new() -> Self;

    // Expect connectivity check
    pub fn expect_connectivity_check(self, result: Result<bool, FleetError>) -> Self;

    // Expect specific command
    pub fn expect_command(self, pattern: &str, response: Result<String, FleetError>) -> Self;

    // Expect command with full output
    pub fn expect_command_full(self, pattern: &str, output: CommandOutput) -> Self;

    // Simulate delay (for timeout testing)
    pub fn with_delay(self, duration: Duration) -> Self;

    // Track concurrency
    pub fn with_concurrency_tracking(
        self,
        current: Arc<AtomicUsize>,
        max: Arc<AtomicUsize>,
    ) -> Self;
}
