### 2. Preset Configurations
\`\`\`rust
impl MockSshExecutor {
    /// All checks pass, worker is healthy
    pub fn all_healthy() -> Self {
        Self::new()
            .expect_connectivity_check(Ok(true))
            .expect_command("df", Ok("5000M"))
            .expect_command("which rsync", Ok("/usr/bin/rsync"))
            .expect_command("which zstd", Ok("/usr/bin/zstd"))
            .expect_command("which rustup", Ok("/home/user/.cargo/bin/rustup"))
            .expect_command("rch-wkr --version", Ok("rch-wkr 1.0.0"))
    }

    /// Worker unreachable (SSH fails)
    pub fn unreachable() -> Self {
        Self::new()
            .expect_connectivity_check(Err(FleetError::ConnectionTimeout))
    }

    /// All workers unreachable
    pub fn all_unreachable() -> Self {
        Self::unreachable()
    }

    /// Simulate slow connection (for timeout tests)
    pub fn slow(delay: Duration) -> Self {
        Self::new().with_delay(delay)
    }
}
